import{_ as t,o as a,c as r,a2 as o}from"./chunks/framework.C766EroN.js";const m=JSON.parse('{"title":"","description":"","frontmatter":{"layout":"home","lastUpdated":"2026-02-26T00:00:00.000Z","hero":{"name":"Ly 开源项目","text":"以爱之名，为技术赋能","tagline":"专注于教育、制造业数字化转型与文化传承的开源解决方案","actions":[{"theme":"brand","text":"OpenClaw 一键部署","link":"#openclaw"},{"theme":"alt","text":"LyEdu 企业培训系统","link":"/projects/lyedu/introduction"},{"theme":"alt","text":"LyGenealogy 屈氏宗谱","link":"/projects/lygenealogy/introduction"},{"theme":"alt","text":"LyMom 制造业运营管理系统","link":"/projects/lymom/introduction"}]},"features":[{"title":"OpenClaw 一键部署","details":"自研安装包，简化 OpenClaw 部署流程，告别手动配置报错，技术小白 1 分钟开箱即用"},{"title":"LyEdu 企业培训系统","details":"轻量化教育类系统，支持在线学习、课程管理、考试中心、证书系统等功能，一键部署私有化培训平台"},{"title":"LyGenealogy 屈氏宗谱","details":"Node.js 族谱数字化平台，Express + Nuxt 3 + Vue Admin，Monorepo；REST API、公共前端与管理后台，支持多族谱、世系树、亲属查询、字辈与文化展示"},{"title":"LyMom 制造业运营管理系统","details":"基于 DDD 架构的现代化 MOM 系统，支持设备管理、生产执行、仓储管理、质量管理等全流程"},{"title":"技术创新","details":"采用现代技术栈，双后端架构，支持微服务部署，为不同场景提供灵活的技术解决方案"},{"title":"用户友好","details":"现代化 UI 设计，多端支持，统一入口，提供良好的用户体验"},{"title":"安全可靠","details":"视频私有化存储、JWT 认证、飞书集成登录，确保系统安全"},{"title":"开源精神","details":"100% 开源，欢迎社区贡献，共同推进数字化转型"}]},"headers":[],"relativePath":"index.md","filePath":"index.md"}'),n={name:"index.md"};function i(l,e,s,d,p,c){return a(),r("div",null,[...e[0]||(e[0]=[o('<h2 id="openclaw" tabindex="-1">OpenClaw 一键部署 <a class="header-anchor" href="#openclaw" aria-label="Permalink to &quot;OpenClaw 一键部署 {#openclaw}&quot;">​</a></h2><div class="openclaw-section"><p>自研安装包，简化 OpenClaw 部署流程，技术小白的福音。1 分钟开箱即用，告别手动配置报错。</p><div class="openclaw-cards" style="display:grid;grid-template-columns:repeat(auto-fit, minmax(260px, 1fr));gap:1rem;margin:1.5rem 0;"><div class="openclaw-card"><strong>一键安装 · 开箱即用</strong> - 官方版 OpenClaw，同步最新更新 - 手动配置报错，一键解决 - 迎合大众与最新趋势 </div><div class="openclaw-card"><strong>简化部署 · 告别繁琐</strong> - 无需逐项配置，安装即运行 - 常见部署问题，内置自动处理 - 降低使用门槛，人人可上手 </div><div class="openclaw-card"><strong>多平台连接 · 随时随地</strong> - 钉钉、飞书、微信、Telegram - 手机即可操作电脑 - 适配主流办公协作工具 </div><div class="openclaw-card"><strong>AI 助手 · 高效赋能</strong> - 一句话完成复杂任务 - 丰富技能生态，覆盖办公场景 - 本地记忆系统，越用越懂你 </div></div><p class="openclaw-cta-wrap" style="text-align:center;margin:1.5rem 0;"><a href="http://39.106.39.125:9999/%E6%A0%BE%E5%AA%9B%E5%85%BB%E8%99%BE_Setup_1.0.0.exe" target="_blank" rel="noopener" class="vp-button brand" style="display:inline-block;"> 立即获取 OpenClaw 一键部署 → </a></p><div class="openclaw-about" style="margin-top:2rem;padding-top:1.5rem;border-top:1px solid rgba(232, 93, 4, 0.2);color:var(--vp-c-text-2);font-size:0.9rem;"><strong>关于我们</strong> — Ly 系列开源项目始于对教育、制造业数字化转型与文化传承的思考。Ly 这个名字来源于我的女儿，象征着希望和未来。愿景：打造高质量开源解决方案；理念：技术多样性、架构合理性、用户体验优先、开源共享。 </div></div><hr><h2 id="项目简介" tabindex="-1">项目简介 <a class="header-anchor" href="#项目简介" aria-label="Permalink to &quot;项目简介&quot;">​</a></h2><div style="display:grid;grid-template-columns:repeat(auto-fit, minmax(320px, 1fr));gap:1.5rem;margin:1.5rem 0;"><div class="project-card" style="padding:1.25rem;border:1px solid var(--vp-c-divider);border-radius:8px;"><h3 id="lyedu-企业培训系统" tabindex="-1">LyEdu 企业培训系统 <a class="header-anchor" href="#lyedu-企业培训系统" aria-label="Permalink to &quot;LyEdu 企业培训系统&quot;">​</a></h3><p><a href="/projects/lyedu/introduction.html">项目介绍 →</a></p><p>100% 开源的企业培训系统，界面美观，操作简单，一键部署私有化培训平台。</p><p><strong>核心功能</strong>：部门/学员管理、在线视频学习、进度追踪、课程评论、考试中心、证书系统、知识中心、任务系统、积分排行、飞书集成</p><p><strong>技术栈</strong>：Vue 3 + TypeScript + Element Plus / uni-app x | SpringBoot 4 / FastAPI | MySQL 8.0+ | Docker</p></div><div class="project-card" style="padding:1.25rem;border:1px solid var(--vp-c-divider);border-radius:8px;"><h3 id="lymom-制造业运营管理系统" tabindex="-1">LyMom 制造业运营管理系统 <a class="header-anchor" href="#lymom-制造业运营管理系统" aria-label="Permalink to &quot;LyMom 制造业运营管理系统&quot;">​</a></h3><p><a href="/projects/lymom/introduction.html">项目介绍 →</a></p><p>面向制造业的现代化 MOM 系统，采用 DDD 架构，业务与技术解耦，支持微服务部署。</p><p><strong>核心优势</strong>：DDD 架构、微服务、设备管理（OPC UA/Modbus）、生产管理、仓储管理、质量管理</p><p><strong>技术栈</strong>：Vue 3 + Element Plus | Spring Boot 3.5.3 + Java 24 | PostgreSQL | EMQX/MQTT | Redis | Prometheus/Grafana</p></div><div class="project-card" style="padding:1.25rem;border:1px solid var(--vp-c-divider);border-radius:8px;"><h3 id="lygenealogy-屈氏宗谱" tabindex="-1">LyGenealogy 屈氏宗谱 <a class="header-anchor" href="#lygenealogy-屈氏宗谱" aria-label="Permalink to &quot;LyGenealogy 屈氏宗谱&quot;">​</a></h3><p><a href="/projects/lygenealogy/introduction.html">项目介绍 →</a>  |  <a href="http://39.106.39.125:9997/" target="_blank" rel="noopener">在线演示 ↗</a></p><p>基于 Node.js 的族谱数字化平台，公共前端（Nuxt 3）+ 管理后台（Vue 3 + Element Plus）+ REST API（Express + TypeScript），pnpm Monorepo，前后端分离。</p><p><strong>核心功能</strong>：多族谱管理、世系树、成员搜索与亲缘查询、字辈查询、百科与新闻、JWT 认证</p><p><strong>技术栈</strong>：Express + Nuxt 3 + Vue 3 + better-sqlite3 | pnpm workspace | Caddy + PM2</p></div></div><hr><h2 id="在线体验" tabindex="-1">在线体验 <a class="header-anchor" href="#在线体验" aria-label="Permalink to &quot;在线体验&quot;">​</a></h2><div style="display:grid;grid-template-columns:repeat(auto-fit, minmax(280px, 1fr));gap:1rem;margin:1.5rem 0;"><a href="http://39.106.39.125:9997/" target="_blank" rel="noopener" style="display:block;padding:1.25rem;border:1px solid var(--vp-c-divider);border-radius:8px;text-decoration:none;color:inherit;transition:border-color 0.25s;"><strong>屈氏宗谱</strong><br><span style="color:var(--vp-c-text-2);font-size:0.9rem;">Node.js 族谱平台 · 族谱检索 · 世系树 · 字辈查询 · 姓氏文化</span><br><code style="font-size:0.85rem;">http://39.106.39.125:9997/</code></a></div><hr><h2 id="如何参与" tabindex="-1">如何参与 <a class="header-anchor" href="#如何参与" aria-label="Permalink to &quot;如何参与&quot;">​</a></h2><p>我们欢迎社区的参与和贡献：</p><ol><li><strong>Star 项目</strong>：如果您觉得项目有价值，欢迎给我们点个 Star</li><li><strong>提交 Issue</strong>：如果您发现问题或有建议，欢迎提交 Issue</li><li><strong>贡献代码</strong>：如果您有兴趣参与开发，欢迎提交 Pull Request</li><li><strong>分享项目</strong>：如果您觉得项目对他人有帮助，欢迎分享给更多人</li></ol><h2 id="联系我们" tabindex="-1">联系我们 <a class="header-anchor" href="#联系我们" aria-label="Permalink to &quot;联系我们&quot;">​</a></h2><ul><li><strong>GitHub</strong>：<a href="https://github.com/quxiangshun" target="_blank" rel="noreferrer">https://github.com/quxiangshun</a></li><li><strong>Gitee</strong>：<a href="https://gitee.com/quxiangshun" target="_blank" rel="noreferrer">https://gitee.com/quxiangshun</a></li><li><strong>GitCode</strong>：<a href="https://gitcode.com/quxiangshun" target="_blank" rel="noreferrer">https://gitcode.com/quxiangshun</a></li><li><strong>邮箱</strong>：735591110@qq.com | <a href="mailto:quxiangshun@gmail.com" target="_blank" rel="noreferrer">quxiangshun@gmail.com</a></li></ul><hr><p>以爱之名，为技术赋能。我们相信，通过开源的力量，能够让技术更加普惠，让数字化转型更加简单。</p>',16)])])}const u=t(n,[["render",i]]);export{m as __pageData,u as default};
